import{_ as r,c as e,o as l,ag as o}from"./chunks/framework.Co20b0ok.js";const T=JSON.parse('{"title":"NTLM PTH和Kerberos PTH以及PTT（GPT生成）","description":"","frontmatter":{},"headers":[],"relativePath":"intranet-security/domain-penetration/NTLM PTH和Kerberos PTH以及PTT（GPT生成）.md","filePath":"intranet-security/domain-penetration/NTLM PTH和Kerberos PTH以及PTT（GPT生成）.md"}'),a={name:"intranet-security/domain-penetration/NTLM PTH和Kerberos PTH以及PTT（GPT生成）.md"};function i(s,t,n,d,h,g){return l(),e("div",null,t[0]||(t[0]=[o('<h1 id="ntlm-pth和kerberos-pth以及ptt-gpt生成" tabindex="-1">NTLM PTH和Kerberos PTH以及PTT（GPT生成） <a class="header-anchor" href="#ntlm-pth和kerberos-pth以及ptt-gpt生成" aria-label="Permalink to &quot;NTLM PTH和Kerberos PTH以及PTT（GPT生成）&quot;">​</a></h1><h2 id="ntlm-和-kerberos-的-pass-the-hash-pth-攻击" tabindex="-1">NTLM 和 Kerberos 的 <strong>Pass-the-Hash (PTH)</strong> 攻击 <a class="header-anchor" href="#ntlm-和-kerberos-的-pass-the-hash-pth-攻击" aria-label="Permalink to &quot;NTLM 和 Kerberos 的 **Pass-the-Hash (PTH)** 攻击&quot;">​</a></h2><p>NTLM 和 Kerberos 的 <strong>Pass-the-Hash (PTH)</strong> 攻击分别是基于两种身份验证机制的攻击技术，其核心思路是直接利用认证凭据（如哈希值或票据）来绕过密码验证。以下是两者的详细对比和说明：</p><hr><h3 id="_1-ntlm-的-pass-the-hash-攻击" tabindex="-1">1. <strong>NTLM 的 Pass-the-Hash 攻击</strong> <a class="header-anchor" href="#_1-ntlm-的-pass-the-hash-攻击" aria-label="Permalink to &quot;1. **NTLM 的 Pass-the-Hash 攻击**&quot;">​</a></h3><ul><li><strong>目标协议</strong>: NTLM (NT LAN Manager)</li><li><strong>攻击对象</strong>: NTLM 哈希值 (通常是 NTLMv1 或 NTLMv2 哈希)</li><li><strong>攻击流程</strong>: <ol><li>攻击者获取了目标用户的 NTLM 哈希值（通过抓取内存、LSASS、抓包或离线密码破解等方式）。</li><li>攻击者使用工具（如 <code>Mimikatz</code>、<code>Pass-The-Hash Toolkit</code> 或 <code>Metasploit</code>）直接注入 NTLM 哈希值，而不是输入明文密码。</li><li>模拟认证请求，通过 NTLM 协议成功登录目标系统（如 SMB、RDP 或其他服务）。</li></ol></li><li><strong>特点</strong>: <ul><li>不需要明文密码，仅依赖 NTLM 哈希。</li><li>常用于 Windows 系统，特别是没有启用 Kerberos 的场景。</li><li>需要有网络上的目标系统支持 NTLM 协议。</li></ul></li><li><strong>工具</strong>: <ul><li>Mimikatz</li><li>Metasploit 模块 (<code>psexec</code> 等)</li><li>Impacket 工具集 (<code>wmiexec.py</code>, <code>psexec.py</code>)</li></ul></li></ul><hr><h3 id="_2-kerberos-的-pass-the-ticket-攻击" tabindex="-1">2. <strong>Kerberos 的 Pass-the-Ticket 攻击</strong> <a class="header-anchor" href="#_2-kerberos-的-pass-the-ticket-攻击" aria-label="Permalink to &quot;2. **Kerberos 的 Pass-the-Ticket 攻击**&quot;">​</a></h3><ul><li><strong>目标协议</strong>: Kerberos</li><li><strong>攻击对象</strong>: Kerberos 票据（TGT 或 TGS）</li><li><strong>攻击流程</strong>: <ol><li>攻击者获取了有效的 Kerberos 票据（通过从受害者系统中提取或伪造）。 <ul><li>TGT (Ticket Granting Ticket): 用于请求服务票据。</li><li>TGS (Ticket Granting Service): 用于访问具体服务。</li></ul></li><li>攻击者将票据加载到当前会话中，伪装为拥有票据的合法用户。</li><li>使用票据向目标服务（如文件共享、数据库或其他应用）请求访问权限。</li></ol></li><li><strong>特点</strong>: <ul><li>不需要用户密码，只需要票据。</li><li>更适用于域环境，尤其是启用了 Kerberos 认证的场景。</li><li>攻击的持续性较高，因为票据可以在有效期内重复使用。</li></ul></li><li><strong>工具</strong>: <ul><li>Mimikatz (<code>kerberos::ptt</code>)</li><li>Rubeus</li><li>Impacket 工具集 (<code>getTGT.py</code>, <code>getST.py</code>)</li></ul></li></ul><hr><h3 id="ntlm-pth-和-kerberos-ptt-的对比" tabindex="-1"><strong>NTLM PTH 和 Kerberos PTT 的对比</strong> <a class="header-anchor" href="#ntlm-pth-和-kerberos-ptt-的对比" aria-label="Permalink to &quot;**NTLM PTH 和 Kerberos PTT 的对比**&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>特性</strong></th><th><strong>NTLM PTH</strong></th><th><strong>Kerberos PTT</strong></th></tr></thead><tbody><tr><td><strong>协议类型</strong></td><td>NTLM</td><td>Kerberos</td></tr><tr><td><strong>依赖凭据</strong></td><td>NTLM 哈希</td><td>Kerberos 票据 (TGT/TGS)</td></tr><tr><td><strong>适用场景</strong></td><td>工作组环境或支持 NTLM 的服务</td><td>域环境，启用了 Kerberos 的服务</td></tr><tr><td><strong>认证持续性</strong></td><td>哈希永久有效（直到密码改变）</td><td>票据有限有效期（但 TGT 可延长）</td></tr><tr><td><strong>工具支持</strong></td><td>Mimikatz, Impacket, Metasploit</td><td>Mimikatz, Rubeus, Impacket</td></tr><tr><td><strong>防御措施</strong></td><td>禁用 NTLM，使用 SMB 签名或仅限 Kerberos</td><td>强化票据管理，启用 PAC 验证和票据加密</td></tr></tbody></table><h3 id="与传统-pass-the-hash-的对比" tabindex="-1"><strong>与传统 Pass-the-Hash 的对比</strong> <a class="header-anchor" href="#与传统-pass-the-hash-的对比" aria-label="Permalink to &quot;**与传统 Pass-the-Hash 的对比**&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>特性</strong></th><th><strong>NTLM Pass-the-Hash</strong></th><th><strong>Kerberos PTH</strong></th></tr></thead><tbody><tr><td><strong>目标协议</strong></td><td>NTLM（基于挑战/响应认证）</td><td>Kerberos（基于票据认证）</td></tr><tr><td><strong>攻击的起点</strong></td><td>使用用户的 NTLM 哈希直接响应认证挑战</td><td>使用用户的 NTLM 哈希向 KDC 请求 Kerberos 票据</td></tr><tr><td><strong>攻击的方式</strong></td><td>伪造 NTLM 认证会话</td><td>模拟用户身份，获取 TGT 并访问资源</td></tr><tr><td><strong>依赖的工具</strong></td><td><code>pth-winexe</code>, <code>impacket</code>, 或手工传递哈希</td><td>Mimikatz、Impacket 等 Kerberos 相关工具</td></tr><tr><td><strong>绕过机制</strong></td><td>避免密码学检查，只需哈希</td><td>依赖 Kerberos 体系的信任关系</td></tr></tbody></table><hr><h3 id="防御措施" tabindex="-1"><strong>防御措施</strong> <a class="header-anchor" href="#防御措施" aria-label="Permalink to &quot;**防御措施**&quot;">​</a></h3><ol><li><strong>针对 NTLM PTH</strong>: <ul><li>禁用 NTLM（或限制其使用）。</li><li>启用 SMB 签名。</li><li>在域控制器上强制使用 Kerberos。</li><li>使用多因子认证（MFA）。</li></ul></li><li><strong>针对 Kerberos PTT</strong>: <ul><li>启用 Kerberos 票据的 PAC 验证。</li><li>减少 Kerberos 票据的有效期。</li><li>定期清除未使用的 TGT。</li><li>使用工具（如 Microsoft ATA 或 Defender for Identity）检测异常的票据使用行为。</li></ul></li></ol><p>通过这些措施，可以大幅降低 Pass-the-Hash 和 Pass-the-Ticket 攻击的成功率。</p><h2 id="当我们获取到-krbtgt-用户的-htlmhash-后是不是能构造-tgt" tabindex="-1">当我们获取到 krbtgt 用户的 htlmhash 后是不是能构造 tgt <a class="header-anchor" href="#当我们获取到-krbtgt-用户的-htlmhash-后是不是能构造-tgt" aria-label="Permalink to &quot;当我们获取到 krbtgt 用户的 htlmhash 后是不是能构造 tgt&quot;">​</a></h2><h3 id="chatgpt-说" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>是的，当我们获取到 <code>krbtgt</code> 用户的 NTLM 哈希后，就可以利用它来伪造 Kerberos 的 <strong>Ticket-Granting Ticket (TGT)</strong>，实现攻击。这种攻击通常被称为 <strong>Golden Ticket 攻击</strong>。</p><hr><h3 id="原理解释" tabindex="-1"><strong>原理解释</strong> <a class="header-anchor" href="#原理解释" aria-label="Permalink to &quot;**原理解释**&quot;">​</a></h3><ol><li><strong>krbtgt 用户的作用</strong>: <ul><li>在 Active Directory 域中，<code>krbtgt</code> 用户是 Kerberos 认证服务的核心账户。</li><li>它的密码（即 NTLM 哈希）用于对所有 TGT 进行签名和验证。</li><li>如果攻击者获得了 <code>krbtgt</code> 的 NTLM 哈希，就能伪造合法的 TGT。</li></ul></li><li><strong>TGT 的构造</strong>: <ul><li>TGT 是 Kerberos 协议中由域控制器 (KDC) 签发的票据，用户凭借 TGT 请求访问其他服务。</li><li>攻击者使用 <code>krbtgt</code> 的 NTLM 哈希，生成伪造的 TGT，并在其中嵌入任意用户的身份信息和权限（例如，域管理员权限）。</li><li>域控制器会认为这个伪造的 TGT 是合法的，因为它使用了正确的 <code>krbtgt</code> 密钥签名。</li></ul></li><li><strong>Golden Ticket 的能力</strong>: <ul><li><strong>完全控制域</strong>：伪造任意用户的 TGT，获取最高权限（如域管理员权限）。</li><li><strong>持久化访问</strong>：只要 <code>krbtgt</code> 密钥未改变，攻击者的伪造票据就永远有效。</li><li><strong>隐蔽性强</strong>：TGT 的使用通常不被直接记录，传统日志分析难以检测。</li></ul></li></ol><hr><h3 id="构造-tgt-的方法" tabindex="-1"><strong>构造 TGT 的方法</strong> <a class="header-anchor" href="#构造-tgt-的方法" aria-label="Permalink to &quot;**构造 TGT 的方法**&quot;">​</a></h3><p>利用工具（如 Mimikatz），可以轻松伪造 TGT。</p><h3 id="使用-mimikatz-构造-tgt" tabindex="-1">使用 Mimikatz 构造 TGT <a class="header-anchor" href="#使用-mimikatz-构造-tgt" aria-label="Permalink to &quot;使用 Mimikatz 构造 TGT&quot;">​</a></h3><p>以下是伪造 Golden Ticket 的步骤：</p><ol><li><p>获取 <code>krbtgt</code> 用户的 NTLM 哈希：</p><ul><li>可以通过工具（如 <code>lsass</code> 或 <code>secretsdump.py</code>）提取。</li></ul></li><li><p>使用 Mimikatz 生成 Golden Ticket：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::golden /user:Administrator /domain:example.com /sid:S-1-5-21-XXXXX /krbtgt:&lt;krbtgt哈希&gt; /id:500</span></span></code></pre></div><p>参数说明：</p><ul><li><code>/user</code>：伪造票据中包含的用户名。</li><li><code>/domain</code>：目标域名。</li><li><code>/sid</code>：域的安全标识符 (SID)，可以通过 <code>whoami /user</code> 获取。</li><li><code>/krbtgt</code>：<code>krbtgt</code> 用户的 NTLM 哈希。</li><li><code>/id</code>：用户的 RID，<code>500</code> 是默认的域管理员 RID。</li></ul></li><li><p>加载伪造的 TGT：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::ptt &lt;ticket_file&gt;</span></span></code></pre></div></li><li><p>使用票据访问目标服务：</p><ul><li>可以直接使用 <code>dir \\\\target_server\\share</code> 或其他 Kerberos 认证的服务。</li></ul></li></ol><hr><h3 id="防御措施-1" tabindex="-1"><strong>防御措施</strong> <a class="header-anchor" href="#防御措施-1" aria-label="Permalink to &quot;**防御措施**&quot;">​</a></h3><ol><li><strong>定期更改 <code>krbtgt</code> 密码</strong>： <ul><li>更改 <code>krbtgt</code> 用户密码会使所有现有票据失效。</li><li>建议每隔 6 个月更改一次，至少更改两次以完全刷新密钥。</li></ul></li><li><strong>启用认证日志监控</strong>： <ul><li>检测异常的票据使用行为（如非正常时间的管理员登录）。</li></ul></li><li><strong>实施更严格的访问控制</strong>： <ul><li>限制对敏感账户（如域管理员和 <code>krbtgt</code>）的访问。</li><li>使用分层的管理员账户（如 JEA/PAW 模型）。</li></ul></li><li><strong>增强票据保护</strong>： <ul><li>启用 Kerberos 的 <code>AES</code> 加密（在域控制器和客户端上）。</li><li>使用 Microsoft Defender for Identity 等工具检测异常的 Kerberos 行为。</li></ul></li></ol><hr><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>获取 <code>krbtgt</code> 的 NTLM 哈希后，确实可以伪造 TGT 并实现 Golden Ticket 攻击。但这种攻击同时伴随着强烈的风险信号，建议企业采取严格的密钥管理和监控措施来降低风险。</p><h2 id="kerberos-的-pth-拿到用户-hash-也可以进行吗" tabindex="-1">kerberos 的 pth 拿到用户 hash 也可以进行吗 <a class="header-anchor" href="#kerberos-的-pth-拿到用户-hash-也可以进行吗" aria-label="Permalink to &quot;kerberos 的 pth 拿到用户 hash 也可以进行吗&quot;">​</a></h2><h3 id="chatgpt-说-1" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-1" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>在 Kerberos 协议中，<strong>Pass-the-Hash (PTH)</strong> 攻击不能直接像 NTLM 一样利用用户的 NTLM 哈希进行身份验证。这是因为 Kerberos 的身份验证机制并不直接依赖用户的 NTLM 哈希，而是基于加密密钥和票据进行操作。然而，攻击者可以通过一些方法间接利用用户的 NTLM 哈希，伪造 Kerberos 票据（类似 PTH 的效果）。以下是详细说明：</p><hr><h3 id="kerberos-是否支持-pth" tabindex="-1"><strong>Kerberos 是否支持 PTH?</strong> <a class="header-anchor" href="#kerberos-是否支持-pth" aria-label="Permalink to &quot;**Kerberos 是否支持 PTH?**&quot;">​</a></h3><p>严格来说，Kerberos 本身不支持直接的 PTH 攻击，但攻击者可以通过以下方式利用用户的 NTLM 哈希：</p><h3 id="_1-利用用户的-ntlm-哈希生成-kerberos-tgt" tabindex="-1">1. <strong>利用用户的 NTLM 哈希生成 Kerberos TGT</strong> <a class="header-anchor" href="#_1-利用用户的-ntlm-哈希生成-kerberos-tgt" aria-label="Permalink to &quot;1. **利用用户的 NTLM 哈希生成 Kerberos TGT**&quot;">​</a></h3><ul><li><p><strong>原理</strong>：</p><p>Kerberos 票据（如 TGT）的加密依赖用户的 Kerberos 密钥，而该密钥可以从用户的 NTLM 哈希派生。</p><ul><li>Kerberos 密钥是用户 NTLM 哈希的一个派生值（通过特定算法生成，如 RC4-HMAC）。</li><li>如果攻击者拥有用户的 NTLM 哈希，就可以伪造 TGT 并伪装成该用户。</li></ul></li><li><p><strong>流程</strong>：</p><ol><li>获取用户的 NTLM 哈希（通过抓包、LSASS 内存提取等方式）。</li><li>使用工具（如 <code>Rubeus</code> 或 <code>Impacket</code>）生成与该用户匹配的 TGT。</li><li>加载伪造的 TGT 并请求访问目标服务（如文件共享、数据库等）。</li></ol></li><li><p><strong>工具</strong>：</p><ul><li><p>Rubeus：这会生成一个与目标用户关联的 TGT，可以进一步用于服务访问。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rubeus asktgt /user:username /rc4:&lt;用户的NTLM哈希&gt;</span></span></code></pre></div></li></ul></li></ul><hr><h3 id="_2-kerberos-tgt-tgs-票据的直接利用-pth-的变体" tabindex="-1">2. <strong>Kerberos TGT/TGS 票据的直接利用 (PTH 的变体)</strong> <a class="header-anchor" href="#_2-kerberos-tgt-tgs-票据的直接利用-pth-的变体" aria-label="Permalink to &quot;2. **Kerberos TGT/TGS 票据的直接利用 (PTH 的变体)**&quot;">​</a></h3><ul><li>如果攻击者获取了用户的 <strong>TGT</strong> 或 <strong>TGS</strong>，可以直接加载并使用这些票据进行身份认证，而无需用户密码或 NTLM 哈希。</li><li>这种攻击通常称为 <strong>Pass-the-Ticket (PTT)</strong>，而不是传统意义上的 PTH。</li><li><strong>工具</strong>： <ul><li><p>Mimikatz：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::ptt &lt;ticket_file&gt;</span></span></code></pre></div></li><li><p>Rubeus：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rubeus ptt /ticket:&lt;ticket_file&gt;</span></span></code></pre></div></li></ul></li></ul><hr><h3 id="pth-和-kerberos-的结合" tabindex="-1"><strong>PTH 和 Kerberos 的结合</strong> <a class="header-anchor" href="#pth-和-kerberos-的结合" aria-label="Permalink to &quot;**PTH 和 Kerberos 的结合**&quot;">​</a></h3><p>在某些情况下，PTH 和 Kerberos 攻击可以结合起来实现：</p><h3 id="_1-ntlm-到-kerberos-的转换" tabindex="-1">1. <strong>NTLM 到 Kerberos 的转换</strong> <a class="header-anchor" href="#_1-ntlm-到-kerberos-的转换" aria-label="Permalink to &quot;1. **NTLM 到 Kerberos 的转换**&quot;">​</a></h3><ul><li>攻击者利用用户的 NTLM 哈希登录支持 NTLM 的服务（如 SMB 或 LDAP）。</li><li>在登录过程中，服务端自动生成 TGT 并将其存储在本地内存中。</li><li>攻击者可以提取这些 Kerberos 凭据并执行 PTT 攻击。</li></ul><h3 id="_2-伪造-tgt-类似-golden-ticket-攻击" tabindex="-1">2. <strong>伪造 TGT（类似 Golden Ticket 攻击）</strong> <a class="header-anchor" href="#_2-伪造-tgt-类似-golden-ticket-攻击" aria-label="Permalink to &quot;2. **伪造 TGT（类似 Golden Ticket 攻击）**&quot;">​</a></h3><ul><li>如果攻击者已经拥有 <code>krbtgt</code> 的 NTLM 哈希，可以直接伪造任意用户的 TGT，而无需该用户的哈希或密码。</li></ul><hr><h3 id="总结-1" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结-1" aria-label="Permalink to &quot;**总结**&quot;">​</a></h3><p>Kerberos 本身无法像 NTLM 那样直接通过用户的 NTLM 哈希完成身份验证，但攻击者可以通过以下方法实现类似效果：</p><ul><li>利用用户的 NTLM 哈希生成 TGT。</li><li>获取并利用现有的 Kerberos 票据（PTT）。</li><li>结合 NTLM PTH 攻击转化为 Kerberos 攻击。</li></ul><p>这些攻击需要一定的权限和工具支持，因此防御策略应集中于以下方面：</p><ol><li>限制对 NTLM 哈希的获取（如保护 LSASS 进程、禁用 NTLM 协议）。</li><li>实施 Kerberos 安全最佳实践（如启用 AES 加密、限制票据有效期）。</li><li>定期监控用户的认证行为和异常票据使用情况。</li></ol><h2 id="使用金票票据是通过票据传递吗" tabindex="-1">使用金票票据是通过票据传递吗 <a class="header-anchor" href="#使用金票票据是通过票据传递吗" aria-label="Permalink to &quot;使用金票票据是通过票据传递吗&quot;">​</a></h2><h3 id="chatgpt-说-2" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-2" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>是的，使用**金票（Golden Ticket）<strong>实际上是通过</strong>票据传递（Pass-the-Ticket, PTT）**的方式实现的。金票攻击的本质是伪造一个伪造的 Kerberos <strong>TGT（Ticket Granting Ticket）</strong>，然后将其传递到当前会话中，让系统认为攻击者是一个合法的用户。</p><hr><h3 id="金票攻击的工作原理" tabindex="-1"><strong>金票攻击的工作原理</strong> <a class="header-anchor" href="#金票攻击的工作原理" aria-label="Permalink to &quot;**金票攻击的工作原理**&quot;">​</a></h3><ol><li><strong>伪造 TGT</strong>： <ul><li>攻击者通过获取域控制器的 <code>krbtgt</code> 用户的哈希值（NTLM 或 AES 密钥）来伪造一个 TGT。</li><li>这个 TGT 由攻击者生成，并使用 <code>krbtgt</code> 的哈希进行加密和签名。因为域控制器会用 <code>krbtgt</code> 的密钥来验证票据的合法性，因此伪造的 TGT会被认为是合法的。</li></ul></li><li><strong>加载票据</strong>： <ul><li>攻击者使用工具（如 Mimikatz）的 <code>kerberos::ptt</code> 功能将伪造的 TGT 直接注入到当前会话中，模拟了合法用户通过 Kerberos 登录的过程。</li></ul></li><li><strong>请求服务票据 (TGS)</strong>： <ul><li>使用伪造的 TGT，攻击者向域控制器请求访问其他服务（如文件共享、SQL 数据库等）的 TGS。</li><li>因为伪造的 TGT被域控制器认为合法，域控制器会颁发对应的 TGS。</li></ul></li><li><strong>访问目标服务</strong>： <ul><li>攻击者通过 TGS 访问目标服务，获取权限，甚至可以伪装成域管理员访问任何资源。</li></ul></li></ol><hr><h3 id="金票攻击是如何通过票据传递实现的" tabindex="-1"><strong>金票攻击是如何通过票据传递实现的</strong> <a class="header-anchor" href="#金票攻击是如何通过票据传递实现的" aria-label="Permalink to &quot;**金票攻击是如何通过票据传递实现的**&quot;">​</a></h3><ol><li><p><strong>获取 TGT</strong>：</p><p>金票是一个自生成的 TGT，与传统的 TGT（由域控制器生成）不同，但作用相同。</p></li><li><p><strong>传递票据</strong>：</p><ul><li>通过 <strong>Pass-the-Ticket (PTT)</strong> 的技术，将金票加载到内存中。</li><li>加载后，操作系统会将其作为合法的票据，用于认证 Kerberos 服务请求。</li></ul></li><li><p><strong>模拟合法用户会话</strong>：</p><ul><li>一旦票据被注入，所有通过 Kerberos 的服务请求都会使用伪造的 TGT。</li><li>通过设置合适的权限（如域管理员权限），攻击者可以对目标系统进行全面控制。</li></ul></li></ol><hr><h3 id="工具实现金票攻击" tabindex="-1"><strong>工具实现金票攻击</strong> <a class="header-anchor" href="#工具实现金票攻击" aria-label="Permalink to &quot;**工具实现金票攻击**&quot;">​</a></h3><h3 id="_1-使用-mimikatz" tabindex="-1">1. 使用 <strong>Mimikatz</strong> <a class="header-anchor" href="#_1-使用-mimikatz" aria-label="Permalink to &quot;1. 使用 **Mimikatz**&quot;">​</a></h3><p>伪造并加载金票的完整流程如下：</p><p><strong>1. 生成金票</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::golden /user:Administrator /domain:example.com /sid:S-1-5-21-XXXXXX /krbtgt:&lt;krbtgt哈希&gt; /id:500</span></span></code></pre></div><ul><li><code>/user</code>：伪装的用户名（如 Administrator）。</li><li><code>/domain</code>：目标域名。</li><li><code>/sid</code>：目标域的 SID。</li><li><code>/krbtgt</code>：<code>krbtgt</code> 用户的哈希值（NTLM 或 AES 密钥）。</li><li><code>/id</code>：用户的 RID，域管理员通常为 <code>500</code>。</li></ul><p><strong>2. 加载金票</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::ptt &lt;生成的ticket.kirbi文件&gt;</span></span></code></pre></div><p><strong>3. 测试访问</strong> 通过金票的 TGT 请求服务，比如访问远程文件共享：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dir \\\\target-server\\shared</span></span></code></pre></div><hr><h3 id="金票-vs-票据传递" tabindex="-1"><strong>金票 vs. 票据传递</strong> <a class="header-anchor" href="#金票-vs-票据传递" aria-label="Permalink to &quot;**金票 vs. 票据传递**&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>特性</strong></th><th><strong>金票攻击 (Golden Ticket)</strong></th><th><strong>票据传递 (Pass-the-Ticket)</strong></th></tr></thead><tbody><tr><td><strong>关键凭据</strong></td><td><code>krbtgt</code> 用户的哈希（伪造 TGT）</td><td>获取到的现成 TGT 或 TGS</td></tr><tr><td><strong>票据生成方式</strong></td><td>由攻击者伪造 TGT</td><td>使用已存在的 TGT/TGS</td></tr><tr><td><strong>持久性</strong></td><td>长期有效（只要 <code>krbtgt</code> 未更改）</td><td>受票据有效期限制（通常为 10 小时）</td></tr><tr><td><strong>适用场景</strong></td><td>完全控制域（伪造任何用户）</td><td>接管已有会话或权限扩展</td></tr></tbody></table><hr><h3 id="防御措施-2" tabindex="-1"><strong>防御措施</strong> <a class="header-anchor" href="#防御措施-2" aria-label="Permalink to &quot;**防御措施**&quot;">​</a></h3><ol><li><strong>定期更改 <code>krbtgt</code> 密码</strong>： <ul><li>更改两次以彻底刷新所有与旧密钥相关的票据。</li><li>避免长期使用同一个 <code>krbtgt</code> 哈希。</li></ul></li><li><strong>加强票据管理</strong>： <ul><li>启用 Kerberos 票据的 PAC 验证。</li><li>减少票据有效期（如 TGT 的默认 10 小时）。</li></ul></li><li><strong>监控和检测</strong>： <ul><li>使用 SIEM 系统检测异常的 Kerberos 行为（如高权限用户的异常登录）。</li><li>部署 Microsoft Defender for Identity，监控域控制器的身份验证请求。</li></ul></li><li><strong>分权管理</strong>： <ul><li>实施分层的管理员账户策略，降低单一用户被攻击的风险。</li><li>限制对 <code>krbtgt</code> 哈希的访问权限。</li></ul></li></ol><p>通过这些措施，可以有效降低金票攻击的成功率，同时提升对 PTT 类攻击的检测能力。</p><p>4o</p><h2 id="假如获取到一个普通用户的-tgt-然后通过-ptt-就能使用这个用户的权限了" tabindex="-1">假如获取到一个普通用户的 tgt，然后通过 ptt 就能使用这个用户的权限了 <a class="header-anchor" href="#假如获取到一个普通用户的-tgt-然后通过-ptt-就能使用这个用户的权限了" aria-label="Permalink to &quot;假如获取到一个普通用户的 tgt，然后通过 ptt 就能使用这个用户的权限了&quot;">​</a></h2><h3 id="chatgpt-说-3" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-3" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>是的，如果攻击者获取了一个普通用户的 TGT（Ticket Granting Ticket），然后通过 <strong>PTT（Pass-the-Ticket）</strong> 技术加载到内存中，就可以完全模拟该普通用户的权限来访问域内资源。</p><hr><h3 id="原理" tabindex="-1"><strong>原理</strong> <a class="header-anchor" href="#原理" aria-label="Permalink to &quot;**原理**&quot;">​</a></h3><ol><li><strong>TGT 的作用</strong>： <ul><li>TGT 是 Kerberos 认证体系中最核心的票据之一。</li><li>它用来向域控制器（KDC）请求服务票据（TGS），然后使用 TGS 访问具体的服务（如文件共享、SQL 数据库、远程桌面等）。</li></ul></li><li><strong>通过 PTT 使用票据</strong>： <ul><li>如果攻击者能够获得普通用户的 TGT，并将其加载到自己的系统中，域控制器会认为这是该用户的合法请求。</li><li>所有通过该 TGT 请求的服务都将受到用户权限的限制，攻击者无法超越该普通用户的权限。</li></ul></li><li><strong>限制</strong>： <ul><li>攻击者在使用普通用户的 TGT时，只能访问该用户原本有权限访问的资源。</li><li>无法直接提升权限（除非进一步利用漏洞或配置错误）。</li></ul></li></ol><hr><h3 id="步骤" tabindex="-1"><strong>步骤</strong> <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;**步骤**&quot;">​</a></h3><h3 id="_1-获取普通用户的-tgt" tabindex="-1">1. <strong>获取普通用户的 TGT</strong> <a class="header-anchor" href="#_1-获取普通用户的-tgt" aria-label="Permalink to &quot;1. **获取普通用户的 TGT**&quot;">​</a></h3><p>攻击者可以通过以下方法获取 TGT：</p><ul><li><strong>内存抓取</strong>：使用 Mimikatz 或其他工具从 LSASS 进程中提取用户的 TGT。</li><li><strong>网络嗅探</strong>：在特定条件下（如不启用加密），可以抓取并解析用户的 Kerberos 认证流量。</li><li><strong>票据导出</strong>：某些已感染的系统可能已经将 TGT 保存在磁盘中。</li></ul><h3 id="_2-加载-tgt" tabindex="-1">2. <strong>加载 TGT</strong> <a class="header-anchor" href="#_2-加载-tgt" aria-label="Permalink to &quot;2. **加载 TGT**&quot;">​</a></h3><p>使用工具（如 Mimikatz）加载 TGT：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kerberos::ptt &lt;ticket_file&gt;</span></span></code></pre></div><p>此操作将票据注入到当前会话的内存中，系统会将其作为默认 Kerberos 凭据。</p><h3 id="_3-模拟普通用户访问资源" tabindex="-1">3. <strong>模拟普通用户访问资源</strong> <a class="header-anchor" href="#_3-模拟普通用户访问资源" aria-label="Permalink to &quot;3. **模拟普通用户访问资源**&quot;">​</a></h3><p>加载 TGT 后，攻击者可以访问普通用户有权限访问的资源，例如：</p><ul><li>网络共享：<code>dir \\\\server\\share</code></li><li>数据库查询：连接数据库服务。</li><li>LDAP 查询：通过 Kerberos 认证的 LDAP 操作。</li></ul><hr><h3 id="提升权限的可能性" tabindex="-1"><strong>提升权限的可能性</strong> <a class="header-anchor" href="#提升权限的可能性" aria-label="Permalink to &quot;**提升权限的可能性**&quot;">​</a></h3><p>虽然直接加载普通用户的 TGT无法提升权限，但攻击者可以结合其他技术扩大攻击范围，例如：</p><ol><li><strong>查找配置错误</strong>： <ul><li>检查普通用户是否有意外高权限（如误配置的目录权限或服务权限）。</li><li>检查是否存在可利用的服务账户或弱密码。</li></ul></li><li><strong>横向移动</strong>： <ul><li>使用普通用户权限访问其他机器，并尝试提取更高权限用户的凭据（如域管理员）。</li><li>例如，通过普通用户权限连接到有管理员登录过的机器，从内存中提取管理员票据。</li></ul></li><li><strong>Kerberos 委派攻击</strong>： <ul><li>如果普通用户账户被配置了 Kerberos 委派权限，攻击者可以滥用这些权限来请求高权限服务的票据。</li></ul></li></ol><hr><h3 id="防御措施-3" tabindex="-1"><strong>防御措施</strong> <a class="header-anchor" href="#防御措施-3" aria-label="Permalink to &quot;**防御措施**&quot;">​</a></h3><ol><li><strong>保护 TGT</strong>： <ul><li>启用 Windows 的 <strong>Credential Guard</strong>，防止 LSASS 内存中的 TGT 被提取。</li><li>配置系统强制使用 Kerberos 加密传输，防止网络嗅探。</li></ul></li><li><strong>最小权限原则</strong>： <ul><li>确保普通用户账户只拥有最低限度的权限。</li><li>定期审核权限配置，避免误配置导致权限扩大。</li></ul></li><li><strong>监控票据活动</strong>： <ul><li>部署 SIEM 或类似工具，检测异常的 Kerberos 活动（如 TGT 的非正常使用）。</li><li>监控用户账户的登录行为，发现异常的权限使用。</li></ul></li><li><strong>限制票据生命周期</strong>： <ul><li>减少 TGT 的有效期（默认 10 小时），降低票据泄露的利用窗口。</li><li>启用票据续签限制，防止票据被长期滥用。</li></ul></li></ol><hr><h3 id="总结-2" tabindex="-1">总结 <a class="header-anchor" href="#总结-2" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>获取普通用户的 TGT，并通过 PTT 技术加载后，可以完全模拟该用户的权限，但攻击者的能力受到该用户权限的限制。尽管如此，攻击者仍可以通过横向移动或其他漏洞利用提升权限，因此需要结合权限管理和行为监控来降低风险。</p><h2 id="那么-pac-里边的签名是每次数据包交换时都要检查吗" tabindex="-1">那么 pac 里边的签名是每次数据包交换时都要检查吗 <a class="header-anchor" href="#那么-pac-里边的签名是每次数据包交换时都要检查吗" aria-label="Permalink to &quot;那么 pac 里边的签名是每次数据包交换时都要检查吗&quot;">​</a></h2><h3 id="chatgpt-说-4" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-4" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>在 Kerberos 协议中，<strong>PAC（Privilege Attribute Certificate）</strong> 的签名并不是在每次数据包交换时都要检查，而是在特定的场景下由服务或域控制器决定是否验证。以下是 PAC 签名的作用、验证机制和具体细节：</p><hr><h3 id="pac-签名的作用" tabindex="-1"><strong>PAC 签名的作用</strong> <a class="header-anchor" href="#pac-签名的作用" aria-label="Permalink to &quot;**PAC 签名的作用**&quot;">​</a></h3><p>PAC 包含用户的权限信息（如组成员身份和特权），并附带数字签名以防止篡改：</p><ol><li><strong>PAC 的组成</strong>： <ul><li>用户的权限信息。</li><li>由 KDC（域控制器）生成的签名（由 <code>krbtgt</code> 密钥加密）。</li><li>服务密钥签名（由目标服务密钥加密，用于服务验证）。</li></ul></li><li><strong>签名的目的</strong>： <ul><li>保证 PAC 的完整性，防止攻击者篡改用户权限信息（如提升用户权限）。</li><li>在需要时，目标服务可以验证 PAC 是否来自合法的 KDC。</li></ul></li></ol><hr><h3 id="签名验证的机制" tabindex="-1"><strong>签名验证的机制</strong> <a class="header-anchor" href="#签名验证的机制" aria-label="Permalink to &quot;**签名验证的机制**&quot;">​</a></h3><p>签名验证并非每次都执行，而是在以下情况下进行：</p><h3 id="_1-初次验证-服务首次访问时" tabindex="-1">1. <strong>初次验证（服务首次访问时）</strong> <a class="header-anchor" href="#_1-初次验证-服务首次访问时" aria-label="Permalink to &quot;1. **初次验证（服务首次访问时）**&quot;">​</a></h3><ul><li>当用户通过 Kerberos 票据访问目标服务时，服务可以选择验证 PAC 的签名： <ul><li>检查 PAC 是否由可信 KDC 生成（验证 <code>krbtgt</code> 签名）。</li><li>检查 PAC 是否完整且未被篡改（验证服务密钥签名）。</li></ul></li><li>默认情况下，大多数服务不会主动验证 PAC 签名，除非配置为强制验证。</li></ul><h3 id="_2-域控制器的验证请求" tabindex="-1">2. <strong>域控制器的验证请求</strong> <a class="header-anchor" href="#_2-域控制器的验证请求" aria-label="Permalink to &quot;2. **域控制器的验证请求**&quot;">​</a></h3><ul><li>如果目标服务不具备验证 PAC 的能力，它可以通过 <code>KDC_VERIFY_PAC</code> 请求将 PAC 转发回域控制器，由域控制器验证签名并返回结果。</li></ul><h3 id="_3-高安全模式下的强制验证" tabindex="-1">3. <strong>高安全模式下的强制验证</strong> <a class="header-anchor" href="#_3-高安全模式下的强制验证" aria-label="Permalink to &quot;3. **高安全模式下的强制验证**&quot;">​</a></h3><ul><li>某些情况下（如敏感系统或启用了特定策略），服务或域控制器会强制检查 PAC 签名，确保票据的合法性。</li></ul><hr><h3 id="性能优化与实际行为" tabindex="-1"><strong>性能优化与实际行为</strong> <a class="header-anchor" href="#性能优化与实际行为" aria-label="Permalink to &quot;**性能优化与实际行为**&quot;">​</a></h3><ol><li><strong>默认行为</strong>： <ul><li>在许多实现中，为了性能考虑，PAC 签名验证并不是每次请求都进行。</li><li>某些普通服务可能完全跳过 PAC 签名验证。</li></ul></li><li><strong>安全增强</strong>： <ul><li>可以启用特定策略（如 Windows 的 <strong>PAC 验证策略</strong>）强制域内服务验证 PAC 签名。</li><li>启用后，所有服务会向域控制器请求 PAC 验证，确保票据真实性。</li></ul></li><li><strong>PAC 验证的负载</strong>： <ul><li>如果在域内广泛启用 PAC 验证，可能会增加域控制器的负载，特别是在大型环境中。</li></ul></li></ol><hr><h3 id="pac-签名与攻击防御" tabindex="-1"><strong>PAC 签名与攻击防御</strong> <a class="header-anchor" href="#pac-签名与攻击防御" aria-label="Permalink to &quot;**PAC 签名与攻击防御**&quot;">​</a></h3><h3 id="金票攻击与-pac-签名的关系" tabindex="-1"><strong>金票攻击与 PAC 签名的关系</strong> <a class="header-anchor" href="#金票攻击与-pac-签名的关系" aria-label="Permalink to &quot;**金票攻击与 PAC 签名的关系**&quot;">​</a></h3><ul><li><strong>金票攻击</strong>：攻击者伪造 TGT 时，也会伪造 PAC。由于伪造的 PAC 使用伪造的 <code>krbtgt</code> 签名，只有攻击者拥有合法的 <code>krbtgt</code> 哈希时，PAC 才能通过验证。</li><li><strong>防御机制</strong>： <ol><li>强制服务验证 PAC 签名（提高攻击门槛）。</li><li>定期更改 <code>krbtgt</code> 密钥，刷新伪造票据的有效性。</li></ol></li></ul><hr><h3 id="如何启用-pac-验证" tabindex="-1"><strong>如何启用 PAC 验证</strong> <a class="header-anchor" href="#如何启用-pac-验证" aria-label="Permalink to &quot;**如何启用 PAC 验证**&quot;">​</a></h3><p>在 Windows 环境中，可以通过组策略或注册表启用 PAC 验证：</p><ol><li><p><strong>组策略</strong></p><ul><li>路径：<code>计算机配置 &gt; Windows 设置 &gt; 安全设置 &gt; 本地策略 &gt; 安全选项</code>。</li><li>设置：启用 PAC 强制验证。</li></ul></li><li><p><strong>注册表修改</strong></p><p>修改以下注册表键值强制启用 PAC 验证：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Kerberos\\Parameters</span></span></code></pre></div><p>添加键值：</p><ul><li><code>ValidateKdcPacSignature</code>，设置为 <code>1</code> 强制验证 PAC 签名。</li></ul></li></ol><hr><h3 id="总结-3" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结-3" aria-label="Permalink to &quot;**总结**&quot;">​</a></h3><p>PAC 签名的验证并不是在每次数据包交换中强制执行，而是在用户初次访问服务或特定安全策略下执行验证。</p><ul><li>默认情况下，许多服务可能不会主动验证 PAC 签名，以平衡性能和安全性。</li><li>在高安全环境中，可以启用强制 PAC 验证策略，增加对伪造票据（如金票）的防御能力。</li><li>需要权衡验证的安全性与对域控制器的性能负载影响。</li></ul><h2 id="假如-pac-开启了-kdc-签名验证-那么我们伪造的-tgt-还有效吗" tabindex="-1">假如 pac 开启了 kdc 签名验证，那么我们伪造的 tgt 还有效吗 <a class="header-anchor" href="#假如-pac-开启了-kdc-签名验证-那么我们伪造的-tgt-还有效吗" aria-label="Permalink to &quot;假如 pac 开启了 kdc 签名验证，那么我们伪造的 tgt 还有效吗&quot;">​</a></h2><h3 id="chatgpt-说-5" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-5" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>如果 <strong>PAC 启用了 KDC 签名验证</strong>，伪造的 TGT可能会失效，具体取决于攻击者是否拥有正确的密钥来伪造合法的 PAC 签名。以下是详细的分析：</p><hr><h3 id="pac-签名验证的关键点" tabindex="-1"><strong>PAC 签名验证的关键点</strong> <a class="header-anchor" href="#pac-签名验证的关键点" aria-label="Permalink to &quot;**PAC 签名验证的关键点**&quot;">​</a></h3><ol><li><strong>PAC 的组成</strong>： <ul><li>PAC 包含用户的权限信息、组信息等内容。</li><li>它附带两个签名： <ul><li><strong>KDC 签名</strong>：由 <code>krbtgt</code> 的密钥生成，用于证明 PAC 是由域控制器创建的。</li><li><strong>服务密钥签名</strong>：由目标服务的密钥生成，用于让服务验证票据是否完整。</li></ul></li></ul></li><li><strong>启用 KDC 签名验证后</strong>： <ul><li>服务端会将 PAC 发送回域控制器，请求验证 <strong>KDC 签名</strong>。</li><li>如果 PAC 的 KDC 签名无效（例如伪造票据时签名不正确），域控制器会拒绝验证，从而导致 TGT 无法使用。</li></ul></li></ol><hr><h3 id="伪造-tgt-的影响" tabindex="-1"><strong>伪造 TGT 的影响</strong> <a class="header-anchor" href="#伪造-tgt-的影响" aria-label="Permalink to &quot;**伪造 TGT 的影响**&quot;">​</a></h3><h3 id="_1-如果攻击者持有-krbtgt-的哈希" tabindex="-1">1. 如果攻击者持有 <strong>krbtgt 的哈希</strong>： <a class="header-anchor" href="#_1-如果攻击者持有-krbtgt-的哈希" aria-label="Permalink to &quot;1. 如果攻击者持有 **krbtgt 的哈希**：&quot;">​</a></h3><ul><li>伪造的 TGT 依然有效。</li><li>攻击者使用 <code>krbtgt</code> 的哈希生成伪造的 PAC，并正确签名 KDC 部分。即使 PAC 验证被启用，伪造的 TGT 仍然可以通过验证。</li></ul><h3 id="_2-如果攻击者不持有-krbtgt-的哈希" tabindex="-1">2. 如果攻击者不持有 <strong>krbtgt 的哈希</strong>： <a class="header-anchor" href="#_2-如果攻击者不持有-krbtgt-的哈希" aria-label="Permalink to &quot;2. 如果攻击者不持有 **krbtgt 的哈希**：&quot;">​</a></h3><ul><li>攻击者无法正确生成 KDC 签名。</li><li>PAC 验证开启后，域控制器会检测到签名不正确，拒绝服务。</li><li>此时伪造的 TGT将失效，攻击失败。</li></ul><hr><h3 id="金票攻击的影响" tabindex="-1"><strong>金票攻击的影响</strong> <a class="header-anchor" href="#金票攻击的影响" aria-label="Permalink to &quot;**金票攻击的影响**&quot;">​</a></h3><p>金票攻击的关键是伪造合法的 TGT，其中包括 PAC 的伪造。启用了 KDC 签名验证后：</p><ul><li>如果攻击者拥有 <code>krbtgt</code> 的哈希： <ul><li>可以生成有效的 PAC 签名，金票攻击依然有效。</li></ul></li><li>如果攻击者没有 <code>krbtgt</code> 的哈希： <ul><li>无法生成有效的 KDC 签名，金票攻击失效。</li></ul></li></ul><hr><h3 id="防御角度的考虑" tabindex="-1"><strong>防御角度的考虑</strong> <a class="header-anchor" href="#防御角度的考虑" aria-label="Permalink to &quot;**防御角度的考虑**&quot;">​</a></h3><ol><li><strong>启用 PAC 验证</strong>： <ul><li>在关键服务上强制启用 PAC 的 KDC 签名验证，可以有效防御未经授权的 TGT 和伪造票据。</li><li>配置方式： <ul><li><strong>组策略</strong>：启用 PAC 签名验证策略。</li><li><strong>注册表</strong>：设置 <code>ValidateKdcPacSignature</code> 为 <code>1</code>。</li></ul></li></ul></li><li><strong>定期更换 <code>krbtgt</code> 密钥</strong>： <ul><li>定期更换 <code>krbtgt</code> 密钥可以使攻击者的伪造票据失效。</li><li>更换两次以确保历史票据无法通过验证。</li></ul></li><li><strong>监控异常票据</strong>： <ul><li>部署 SIEM 系统，监控异常的 PAC 验证失败日志。</li><li>在域控制器日志中查找相关事件（如 4769 或 PAC 验证失败的记录）。</li></ul></li></ol><hr><h3 id="总结-4" tabindex="-1"><strong>总结</strong> <a class="header-anchor" href="#总结-4" aria-label="Permalink to &quot;**总结**&quot;">​</a></h3><p>当 PAC 验证启用且攻击者未能获取 <code>krbtgt</code> 的哈希时，伪造的 TGT 将失效，攻击无法继续。如果攻击者已获取 <code>krbtgt</code> 的哈希，那么即使启用了 PAC 签名验证，伪造的 TGT 依然可以有效使用。因此，<strong>保护 <code>krbtgt</code> 密钥和启用 PAC 签名验证是防御伪造票据攻击的关键措施</strong>。</p><h2 id="那么-kdc-用户加密就是指-krbtgt-用户的-hash-加密" tabindex="-1">那么 kdc 用户加密就是指 krbtgt 用户的 hash 加密 <a class="header-anchor" href="#那么-kdc-用户加密就是指-krbtgt-用户的-hash-加密" aria-label="Permalink to &quot;那么 kdc 用户加密就是指 krbtgt 用户的 hash 加密&quot;">​</a></h2><h3 id="chatgpt-说-6" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-6" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>是的，<strong>KDC 用户加密</strong>通常指的是使用 <strong><code>krbtgt</code> 用户的 NTLM 哈希（或 Kerberos 密钥派生值）</strong> 来对 Kerberos 票据进行加密。这是 Kerberos 协议中票据安全的核心机制之一。</p><hr><h3 id="krbtgt-用户的角色" tabindex="-1"><strong><code>krbtgt</code> 用户的角色</strong> <a class="header-anchor" href="#krbtgt-用户的角色" aria-label="Permalink to &quot;**`krbtgt` 用户的角色**&quot;">​</a></h3><ol><li><strong><code>krbtgt</code> 用户账户</strong>： <ul><li>是域内专门为 Kerberos 认证而设置的账户。</li><li>它的密钥（基于其 NTLM 哈希）被域控制器用来加密和签名 Kerberos 票据。</li></ul></li><li><strong><code>krbtgt</code> 密钥的作用</strong>： <ul><li>加密 <strong>TGT（Ticket Granting Ticket）</strong>。</li><li>为 <strong>PAC（Privilege Attribute Certificate）</strong> 生成签名，证明票据来自合法的 KDC。</li></ul></li></ol><hr><h3 id="加密与签名的细节" tabindex="-1"><strong>加密与签名的细节</strong> <a class="header-anchor" href="#加密与签名的细节" aria-label="Permalink to &quot;**加密与签名的细节**&quot;">​</a></h3><ol><li><strong>TGT 的加密</strong>： <ul><li>当用户向 KDC 请求 TGT 时，KDC 使用 <strong><code>krbtgt</code> 的密钥</strong>对 TGT 进行加密。</li><li>加密后的 TGT中包含用户的 PAC 数据和其他信息。</li><li>客户端本身无法解密 TGT，因为只有 KDC 持有 <code>krbtgt</code> 的密钥。</li></ul></li><li><strong>PAC 的签名</strong>： <ul><li>PAC 包含用户的权限信息（如组成员身份）。</li><li>KDC 使用</li></ul></li></ol><h2 id="金票后访问服务还需要和tsg交互得到st吗" tabindex="-1">金票后访问服务还需要和tsg交互得到st吗 <a class="header-anchor" href="#金票后访问服务还需要和tsg交互得到st吗" aria-label="Permalink to &quot;金票后访问服务还需要和tsg交互得到st吗&quot;">​</a></h2><h3 id="chatgpt-说-7" tabindex="-1">ChatGPT 说： <a class="header-anchor" href="#chatgpt-说-7" aria-label="Permalink to &quot;ChatGPT 说：&quot;">​</a></h3><p>ChatGPT</p><p>是的，**金票（Golden Ticket）**攻击中，使用伪造的 TGT 后，仍需要通过与 KDC 交互来获取 <strong>TGS（Ticket Granting Service，服务票据）</strong>，从而得到访问目标服务所需的 <strong>ST（Service Ticket）</strong>。</p><hr><h3 id="金票与-tgs-的关系" tabindex="-1"><strong>金票与 TGS 的关系</strong> <a class="header-anchor" href="#金票与-tgs-的关系" aria-label="Permalink to &quot;**金票与 TGS 的关系**&quot;">​</a></h3><ol><li><strong>伪造 TGT 的作用</strong>： <ul><li>金票本质上是伪造的 TGT。</li><li>TGT 的作用是向 KDC 证明用户的身份，允许用户进一步请求 TGS（也称为 ST，用于访问具体服务）。</li></ul></li><li><strong>请求 TGS（ST）</strong>： <ul><li>在使用金票时，攻击者向 KDC 发送伪造的 TGT，并请求目标服务的 TGS。</li><li>KDC 验证 TGT 中的 PAC 数据及签名（如果 PAC 验证未严格配置，则伪造的 TGT可能通过验证）。</li><li>如果验证通过，KDC 会生成并返回目标服务的 TGS。</li></ul></li><li><strong>访问目标服务</strong>： <ul><li>攻击者使用从 KDC 获取到的 TGS（即 ST），向目标服务进行认证，并最终访问服务。</li></ul></li></ol><hr><h3 id="为什么金票仍需要-tgs" tabindex="-1"><strong>为什么金票仍需要 TGS？</strong> <a class="header-anchor" href="#为什么金票仍需要-tgs" aria-label="Permalink to &quot;**为什么金票仍需要 TGS？**&quot;">​</a></h3><ul><li><strong>Kerberos 的安全设计</strong>： <ul><li>Kerberos 协议中，TGT 是一个授权证明，但它不能直接用于访问具体服务。</li><li>访问每个服务时，需要用 TGT 请求生成专门的 TGS，TGS 中包含服务端的加密信息。</li></ul></li><li><strong>目标服务依赖 TGS 验证</strong>： <ul><li>目标服务仅接受 KDC 签名的 TGS，而不接受直接使用 TGT。</li><li>即使 TGT 是伪造的，只要 KDC 认可了 TGT，并生成了 TGS，服务端会信任这个 TGS。</li></ul></li></ul><hr><h3 id="金票与-tgs-的流程总结" tabindex="-1"><strong>金票与 TGS 的流程总结</strong> <a class="header-anchor" href="#金票与-tgs-的流程总结" aria-label="Permalink to &quot;**金票与 TGS 的流程总结**&quot;">​</a></h3><ol><li>攻击者通过伪造的 TGT，冒充合法用户身份。</li><li>使用伪造的 TGT，向 KDC 请求目标服务的 TGS。</li><li>使用从 KDC 获取的 TGS，与目标服务交互并完成认证。</li><li>最终，使用合法的 TGS 访问目标服务。</li></ol>',198)]))}const b=r(a,[["render",i]]);export{T as __pageData,b as default};
